INSERT INTO wp_term_relationships (object_id, term_taxonomy_id, term_order) VALUES (1, 1, 0);
INSERT INTO wp_posts (post_author, post_date, post_date_gmt, post_content, post_title, post_status, comment_status, post_name, post_modified, post_modified_gmt, guid, post_type, comment_count) VALUES (1, '2026-07-15 01:23:00', '2026-07-15 01:23:00', 'Welcome to WordPress. This is not the famous five-minute install: it is the famous five-minute page load. The PHP interpreter, MySQL 5.7 embedded server, wp_posts table, and theme rendering all happen inside your browser tab.', 'Hello world, from browser-side WordPress', 'publish', 'open', 'hello-world-from-browser-side-wordpress', '2026-07-15 01:23:00', '2026-07-15 01:23:00', './?p=1', 'post', 0);
INSERT INTO wp_term_relationships (object_id, term_taxonomy_id, term_order) VALUES (2, 1, 0);
INSERT INTO wp_posts (post_author, post_date, post_date_gmt, post_content, post_title, post_status, comment_status, post_name, post_modified, post_modified_gmt, guid, post_type, comment_count) VALUES (1, '2026-07-14 02:23:00', '2026-07-14 02:23:00', 'The database engine here is Oracle MySQL 5.7.44 compiled to WebAssembly. WordPress still supports the MySQL 5.x family, so this dump uses ordinary MyISAM WordPress tables and avoids modern server-side conveniences like a server.', 'Choosing a WordPress for MySQL 5.7.44', 'publish', 'open', 'choosing-a-wordpress-for-mysql-5744', '2026-07-14 02:23:00', '2026-07-14 02:23:00', './?p=2', 'post', 0);
INSERT INTO wp_term_relationships (object_id, term_taxonomy_id, term_order) VALUES (3, 1, 0);
INSERT INTO wp_posts (post_author, post_date, post_date_gmt, post_content, post_title, post_status, comment_status, post_name, post_modified, post_modified_gmt, guid, post_type, comment_count) VALUES (1, '2026-07-13 03:23:00', '2026-07-13 03:23:00', 'There is no wp-admin setup screen because setup already happened in site/dump.sql. The browser fetches a cached dump, replays it into libmysqld, and then PHP renders a blog from wp_options, wp_posts, and wp_comments.', 'The cached database is the install wizard', 'publish', 'open', 'the-cached-database-is-the-install-wizard', '2026-07-13 03:23:00', '2026-07-13 03:23:00', './?p=3', 'post', 0);
INSERT INTO wp_term_relationships (object_id, term_taxonomy_id, term_order) VALUES (4, 1, 0);
INSERT INTO wp_posts (post_author, post_date, post_date_gmt, post_content, post_title, post_status, comment_status, post_name, post_modified, post_modified_gmt, guid, post_type, comment_count) VALUES (1, '2026-07-12 04:23:00', '2026-07-12 04:23:00', 'Object cache? The object is cache. Cron? Time has no meaning inside this tab. XML-RPC? Please do not give this architecture a remote procedure call surface.', 'Plugins we are proud not to support', 'publish', 'open', 'plugins-we-are-proud-not-to-support', '2026-07-12 04:23:00', '2026-07-12 04:23:00', './?p=4', 'post', 0);
INSERT INTO wp_term_relationships (object_id, term_taxonomy_id, term_order) VALUES (5, 1, 0);
INSERT INTO wp_posts (post_author, post_date, post_date_gmt, post_content, post_title, post_status, comment_status, post_name, post_modified, post_modified_gmt, guid, post_type, comment_count) VALUES (1, '2026-07-11 05:23:00', '2026-07-11 05:23:00', 'We profiled WordPress-in-the-browser. The flame graph is now several very wide bars wearing a trench coat. The second visit is faster only because the browser cache has accepted its fate.', 'Performance Update', 'publish', 'open', 'performance-update', '2026-07-11 05:23:00', '2026-07-11 05:23:00', './?p=5', 'post', 0);
